#include <unordered_map>
#include <climits>

using namespace std;

struct State {
    long long cost;
    int i;
    int j;
    int step;

    bool operator>(const State& other) const {
        return cost > other.cost;
    }
};

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    if (m == 1 && n == 1) {
        return (0 + 1) * (0 + 1);
    }

    vector<pair<int, int>> directions = {{0, 1}, {1, 0}};
    priority_queue<State, vector<State>, greater<State>> heap;
    long long initial_cost = (0 + 1) * (0 + 1);
    heap.push({initial_cost, 0, 0, 1});

    unordered_map<int, unordered_map<int, unordered_map<int, long long>>> visited;
    visited[0][0][1] = initial_cost;

    while (!heap.empty()) {
        State current = heap.top();
        heap.pop();

        long long current_cost = current.cost;
        int i = current.i;
        int j = current.j;
        int step = current.step;

        if (i == m - 1 && j == n - 1) {
            return current_cost;
        }

        if (step % 2 == 1) {
            // Odd step: move right or down
            for (auto& dir : directions) {
                int ni = i + dir.first;
                int nj = j + dir.second;
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    long long new_cost = current_cost + (ni + 1) * (nj + 1);
                    int new_step = step + 1;
                    int key_step = new_step % 2;
                    if (visited[ni][nj].find(key_step) == visited[ni][nj].end() || new_cost < visited[ni][nj][key_step]) {
                        visited[ni][nj][key_step] = new_cost;
                        heap.push({new_cost, ni, nj, new_step});
                    }
                }
            }
        } else {
            // Even step: wait
            long long new_cost = current_cost + waitCost[i][j];
            int new_step = step + 1;
            int key_step = new_step % 2;
            if (visited[i][j].find(key_step) == visited[i][j].end() || new_cost < visited[i][j][key_step]) {
                visited[i][j][key_step] = new_cost;
                heap.push({new_cost, i, j, new_step});
            }
        }
    }

    return -1;
}
